from lxml import etree
from io import StringIO

def process_soap_request(soap_request_xml, dtd_string):
    # Parse the DTD for validation
    dtd = etree.DTD(StringIO(dtd_string))

    # Parse the SOAP XML
    tree = etree.fromstring(soap_request_xml)
    
    # Validate XML against DTD
    if not dtd.validate(tree):
        raise ValueError("XML does not conform to the DTD")

    # Define namespaces if needed
    namespaces = {
        'soap': 'http://schemas.xmlsoap.org/soap/envelope/'
    }

    # Extract the SOAP body
    body = tree.find('.//soap:Body', namespaces)

    if body is None:
        raise ValueError("SOAP Body not found in the request")

    # Return the string representation of the body
    return etree.tostring(body, pretty_print=True).decode()